module RefModule(
    input clk,
    input rst,
    input en,
    output reg [7:0] q
    );
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (rst) begin
            q <= 8'b00000000;
        end else if (en) begin
            q <= q + 1;
        end
    end
endmodule
